import React from "react";
import { useNavigate } from "react-router-dom";


interface SidebarProps {
    activeLink: string;
    onLinkClick: (link: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeLink, onLinkClick }) => {
    const navigate = useNavigate();

    return (
        <div className="sidebar-container">
            <button
                className={activeLink === "inventory" ? "active" : ""}
                onClick={() => { onLinkClick("inventory"); navigate("/inventory"); }}
            >
                Inventory
            </button>
            <button
                className={activeLink === "alerts" ? "active" : ""}
                onClick={() => { onLinkClick("alerts"); navigate("/alerts"); }}
            >
                Alerts
            </button>
            <button
                className={activeLink === "analytics" ? "active" : ""}
                onClick={() => { onLinkClick("analytics"); navigate("/analytics"); }}
            >
                Analytics
            </button>
            <button
                className={activeLink === "settings" ? "active" : ""}
                onClick={() => { onLinkClick("settings"); navigate("/settings"); }}
            >
                Settings
            </button>
            <button
                className={activeLink === "help" ? "active" : ""}
                onClick={() => { onLinkClick("help"); navigate("/help"); }}
            >
                Help
            </button>
        </div>
    );
};

export default Sidebar;
